#include"stdio.h" 
int p(int n){ 
  if(n==0) 
    return 5; 
  else 
    return 2*p(n-1); } 
int s(int n){ 
    if(n==0)
      return 5; 
    else 
      return p(n)+s(n-1); } 
int rest(int N){
    int i=0; 
    while(i<30){ 
      if((N-s(i))<p(i+1) && (N-s(i))>=0) 
	return N-s(i);
      else if(N<5) 
	return N;
    i++; }} 
int expo(int N){ 
  int i=0; 
  while(i<30){ 
    if((N-s(i))<p(i+1) && (N-s(i))>=0) 
      return i; 
    else if(N<5) 
      return 0; 
  i++; }} 
int main(){ 
  int M; 
  scanf("%d",&M);
if(M>4){
  double s=5*rest(M);
  double q=p(expo(M)+1);
  double r=s/q;

   if(0<r&&r<=1) 
   	 printf("Sheldon\n"); 
   else if(1<r&&r<=2) 
     printf("Leonard\n"); 
   else if(2<r&&r<=3) 
     printf("Penny\n"); 
   else if(3<r&&r<=4) 
     printf("Rajesh\n"); 
   else if(4<r&&r<=5) 
     printf("Howard\n"); 
   else 
	 printf("Howard\n"); }
else
	if(M==1)
	printf("Sheldon\n");
	if(M==2)
	printf("Leonard\n");
	if(M==3)
	printf("Penny\n");
	if(M==4)
	printf("Rajesh\n");

return 0; }

