fn main() {
    let (on, ) = R!(u64);
    let names = vec!["Sheldon".to_string(), "Leonard".to_string(), "Penny".to_string(), "Rajesh".to_string(), "Howard".to_string()];

    let mut n: u64 = on - 1;
    let mut seg: u64 = 1;
    while n >= seg * 5 {
        n -= seg * 5;
        seg *= 2;
    }
    println!("{}", names[(n / seg) as usize]);
